function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function uniqueBy(items, getKey) {
  const seen = new Set();

  return items.filter((item) => {
    const key = getKey(item);

    if (!key || seen.has(key)) {
      return false;
    }

    seen.add(key);
    return true;
  });
}

const rows = $input.all()
  .map((item) => item.json)
  .filter((row) => row && typeof row === 'object');

const context =
  rows.find((row) => row.context)?.context ||
  rows.find((row) => row.kind === 'releaseControl')?.context ||
  {};

const commits = rows.filter((row) => row.kind === 'commitRecord');
const issues = rows.filter((row) => row.kind === 'issueRecord');

const primarySis = issues.filter((row) => row.role === 'primary');
const relatedSis = issues.filter((row) => row.role === 'related');
const recs = issues.filter((row) => row.role === 'rec');

const commitToSis = [];

for (const row of commits) {
  const sha = row.github?.commit?.sha || null;

  for (const sisKey of asArray(row.originSisKeys)) {
    if (!sha || !sisKey) {
      continue;
    }

    commitToSis.push({
      commitSha: sha,
      sisKey,
      source: row.sisDetection?.source || 'commitMessage',
    });
  }
}

const sisToRec = [];
const dependencies = [];

for (const row of [...primarySis, ...relatedSis]) {
  const issue = row.issue || {};
  const relationships = issue.relationships || issue.normalized?.relationships || {};

  for (const recKey of asArray(relationships.recKeys)) {
    if (!row.issueKey || !recKey) {
      continue;
    }

    sisToRec.push({
      sisKey: row.issueKey,
      recKey,
      source: 'jira',
    });
  }

  for (const relatedSisKey of asArray(relationships.relatedSisKeys)) {
    if (!row.issueKey || !relatedSisKey) {
      continue;
    }

    dependencies.push({
      fromSisKey: row.issueKey,
      toSisKey: relatedSisKey,
      source: 'jira',
    });
  }
}

function preserveCommit(row) {
  const commit = row.github?.commit || {};

  return {
    ...commit,
    originSisKeys: asArray(row.originSisKeys),
    sisDetection: row.sisDetection || null,
  };
}

function preserveIssue(row) {
  const issue = row.issue || {};
  const normalized = issue.normalized || {};
  const relationships = issue.relationships || {};
  const evidence = issue.evidence || {};

  return {
    role: row.role,
    key: row.issueKey,
    browseUrl: issue.browseUrl || null,
    fetchStatus: issue.fetchStatus || null,
    originCommitShas: asArray(row.originCommitShas),
    relatedFrom: row.relatedFrom || [],
    summary: normalized.summary || null,
    issueType: normalized.issueType || null,
    status: normalized.status || null,
    resolution: normalized.resolution || null,
    priority: normalized.priority || null,
    assignee: normalized.assignee || null,
    labels: asArray(normalized.labels),
    components: asArray(normalized.components),
    fixVersions: asArray(normalized.fixVersions),
    description: normalized.description || normalized.descriptionText || null,
    descriptionText: normalized.descriptionText || normalized.description || null,
    descriptionTruncated: Boolean(normalized.descriptionTruncated),
    relationships,
    comments: asArray(evidence.comments),
    worklogs: asArray(evidence.worklogs),
    histories: asArray(evidence.histories),
    activityScanned: evidence.activityScanned || null,
    fetchErrors: asArray(row.fetchErrors),
    rawIssue: issue,
  };
}

const release = {
  schemaVersion: 'jsat-release-v5',

  release: {
    repository:
      context.repoOwner && context.repoName
        ? `${context.repoOwner}/${context.repoName}`
        : null,

    repoOwner: context.repoOwner || null,
    repoName: context.repoName || null,
    currentVersion: context.currentVersion || null,
    currentRef: context.currentRef || null,
    previousTag: context.previousTag || null,
    compareMeta: context.compareMeta || null,
  },

  commits: commits.map(preserveCommit),

  workItems: uniqueBy(
    [...primarySis, ...relatedSis]
      .map(preserveIssue)
      .filter((issue) => issue.key),
    (issue) => issue.key
  ),

  recItems: uniqueBy(
    recs
      .map(preserveIssue)
      .filter((issue) => issue.key),
    (issue) => issue.key
  ),

  relationships: {
    commitToSis: uniqueBy(
      commitToSis,
      (relation) => `${relation.commitSha}|${relation.sisKey}`
    ),

    sisToRec: uniqueBy(
      sisToRec,
      (relation) => `${relation.sisKey}|${relation.recKey}`
    ),

    dependencies: uniqueBy(
      dependencies,
      (relation) => `${relation.fromSisKey}|${relation.toSisKey}`
    ),
  },

  diagnostics: {
    stats: {
      commits: commits.length,
      primarySis: primarySis.length,
      relatedSis: relatedSis.length,
      recs: recs.length,
      commitsWithFiles: commits.filter(
        (row) => asArray(row.github?.commit?.files).length > 0
      ).length,
      filesTotal: commits.reduce(
        (total, row) =>
          total + asArray(row.github?.commit?.files).length,
        0
      ),
      sisWithComments: [...primarySis, ...relatedSis].filter((row) => {
        const issue = row.issue || {};
        return asArray(issue.evidence?.comments).length > 0;
      }).length,
    },

    commitsWithoutSIS: commits
      .filter((row) => !asArray(row.originSisKeys).length)
      .map((row) => ({
        sha: row.github?.commit?.sha || null,
        message: row.github?.commit?.message || null,
        isMergeCommit: Boolean(row.github?.commit?.isMergeCommit),
      })),

    sisWithoutREC: [...primarySis, ...relatedSis]
      .filter((row) => !asArray(row.issue?.relationships?.recKeys).length)
      .map((row) => row.issueKey)
      .filter(Boolean),
  },
};

const rawText = JSON.stringify(release);

return {
  json: {
    rawRelease: release,
    rawFileName: `jsat-release-${context.currentVersion || 'unknown'}.json`,
    batchCommitSize: Number(context.batchCommitSize || 5),
    batchIndex: context.batchIndex || '',
    localAiBaseUrl: String(context.localAiBaseUrl || 'http://localhost:11434').trim() || 'http://localhost:11434',
    localAiModel: String(context.localAiModel || 'qwen3:32b').trim() || 'qwen3:32b',
    aiPayloadMeta: {
      rawReleaseChars: rawText.length,
      maxAiPayloadChars: Math.max(
        60000,
        Math.min(Number(context.maxAiPayloadChars || 180000), 260000)
      ),
      note: 'The AI prompt is built separately as structured technical evidence. rawRelease retains the complete audit payload.',
    },
  },
};

const source = $json.rawRelease || {};

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function cut(value, max) {
  if (value === null || value === undefined) {
    return null;
  }

  const result = String(value).trim();

  if (!result) {
    return null;
  }

  return result.length > max
    ? `${result.slice(0, max)}â€¦`
    : result;
}

function getIssueBody(row) {
  return row?.normalized || row?.issue || row?.jira || row || {};
}

function getIssueFields(issue) {
  return issue?.fields || {};
}

function normalizeComment(comment) {
  if (typeof comment === 'string') {
    return {
      author: null,
      created: null,
      body: cut(comment, 1600),
    };
  }

  return {
    author:
      comment?.author?.displayName ||
      comment?.author?.name ||
      comment?.author?.emailAddress ||
      comment?.author ||
      null,

    created: comment?.created || comment?.date || null,

    body: cut(
      comment?.body ||
      comment?.text ||
      comment?.content ||
      comment?.comment ||
      '',
      1600
    ),
  };
}

function normalizeWorklog(worklog) {
  if (typeof worklog === 'string') {
    return {
      author: null,
      started: null,
      timeSpent: null,
      comment: cut(worklog, 1000),
    };
  }

  return {
    author:
      worklog?.author?.displayName ||
      worklog?.author?.name ||
      worklog?.author ||
      null,

    started: worklog?.started || null,
    timeSpent:
      worklog?.timeSpent ||
      worklog?.timeSpentSeconds ||
      null,

    comment: cut(
      worklog?.comment ||
      worklog?.body ||
      worklog?.text ||
      '',
      1000
    ),
  };
}

function normalizeHistory(history) {
  return {
    author:
      history?.author?.displayName ||
      history?.author?.name ||
      history?.author ||
      null,

    created: history?.created || null,

    items: asArray(history?.items)
      .slice(0, 20)
      .map((item) => ({
        field: item?.field || null,
        from: item?.fromString || item?.from || null,
        to: item?.toString || item?.to || null,
      })),
  };
}

function normalizeLinkedIssue(link) {
  return {
    key:
      link?.key ||
      link?.issueKey ||
      link?.outwardIssue?.key ||
      link?.inwardIssue?.key ||
      null,

    summary: cut(
      link?.summary ||
      link?.outwardIssue?.fields?.summary ||
      link?.inwardIssue?.fields?.summary ||
      '',
      500
    ),

    relation:
      link?.relation ||
      link?.linkType ||
      link?.type?.name ||
      link?.type ||
      null,
  };
}

function normalizeFile(file, includePatch) {
  return {
    path: file?.filename || file?.path || null,
    status: file?.status || null,
    additions: file?.additions ?? null,
    deletions: file?.deletions ?? null,
    changes: file?.changes ?? null,
    patch: includePatch ? cut(file?.patch, 900) : null,
  };
}

const release = source.release || {};
const rawCommits = asArray(source.commits);
const rawWorkItems = asArray(source.workItems);
const rawRecItems = asArray(source.recItems);
const relations = source.relationships || {};

const commitsBySha = new Map();

for (const commit of rawCommits) {
  if (commit?.sha) {
    commitsBySha.set(commit.sha, commit);
  }
}

const sisToCommitShas = new Map();

for (const relation of asArray(relations.commitToSis)) {
  if (!relation?.sisKey || !relation?.commitSha) {
    continue;
  }

  if (!sisToCommitShas.has(relation.sisKey)) {
    sisToCommitShas.set(relation.sisKey, []);
  }

  sisToCommitShas.get(relation.sisKey).push(relation.commitSha);
}

const sisToRecKeys = new Map();

for (const relation of asArray(relations.sisToRec)) {
  if (!relation?.sisKey || !relation?.recKey) {
    continue;
  }

  if (!sisToRecKeys.has(relation.sisKey)) {
    sisToRecKeys.set(relation.sisKey, []);
  }

  sisToRecKeys.get(relation.sisKey).push(relation.recKey);
}

function buildCommitEvidence(commit, includePatch) {
  return {
    sha: commit.sha || null,
    shortSha: commit.sha ? String(commit.sha).slice(0, 10) : null,
    message: cut(commit.message, 1200),
    date: commit.date || null,
    author: commit.author || null,
    isMergeCommit: Boolean(commit.isMergeCommit),
    detailStatus: commit.detailStatus || null,
    stats: commit.stats || null,
    filesTotal: Number(commit.filesTotal || asArray(commit.files).length || 0),
    files: asArray(commit.files)
      .slice(0, 35)
      .map((file) => normalizeFile(file, includePatch)),
    fetchError: commit.fetchError || null,
  };
}

function buildIssueEvidence(row, type) {
  const issue = getIssueBody(row);
  const fields = getIssueFields(issue);
  const key = row?.key || issue?.key || null;

  const linkedShas = unique([
    ...asArray(row?.originCommitShas),
    ...asArray(issue?.originCommitShas),
    ...asArray(sisToCommitShas.get(key)),
  ]);

  const linkedCommits = linkedShas
    .map((sha) => commitsBySha.get(sha))
    .filter(Boolean)
    .map((commit) =>
      buildCommitEvidence(
        commit,
        // Patch solo cuando hay pocos commits; los archivos siempre se incluyen.
        linkedShas.length <= 6
      )
    );

  const comments = asArray(
    issue?.comments ||
    issue?.commentRows ||
    issue?.comment?.comments ||
    row?.comments
  )
    .map(normalizeComment)
    .filter((comment) => comment.body)
    .sort((a, b) => {
      const left = Date.parse(a?.created || '') || 0;
      const right = Date.parse(b?.created || '') || 0;
      return right - left;
    })
    .slice(0, 2);

  const worklogs = asArray(
    issue?.worklogs ||
    issue?.worklogRows ||
    issue?.worklog?.worklogs ||
    row?.worklogs
  )
    .slice(0, 20)
    .map(normalizeWorklog);

  const changelog = asArray(
    issue?.histories ||
    issue?.changelog?.histories ||
    row?.histories ||
    row?.changelog?.histories
  )
    .slice(0, 30)
    .map(normalizeHistory);

  return {
    type,
    key,

    summary: cut(
      issue?.summary ||
      fields?.summary ||
      row?.summary ||
      '',
      1500
    ),

    description: cut(
      issue?.description ||
      fields?.description ||
      row?.description ||
      '',
      5000
    ),

    status:
      issue?.status ||
      fields?.status?.name ||
      row?.status ||
      null,

    issueType:
      issue?.issueType ||
      fields?.issuetype?.name ||
      row?.issueType ||
      null,

    priority:
      issue?.priority ||
      fields?.priority?.name ||
      row?.priority ||
      null,

    assignee:
      issue?.assignee ||
      fields?.assignee?.displayName ||
      null,

    labels: asArray(issue?.labels || fields?.labels || row?.labels).slice(0, 30),

    relatedRecKeys: unique([
      ...asArray(row?.relatedRecKeys),
      ...asArray(issue?.relationships?.recKeys),
      ...asArray(sisToRecKeys.get(key)),
    ]),

    relatedSisKeys: unique([
      ...asArray(row?.relatedSisKeys),
      ...asArray(issue?.relationships?.relatedSisKeys),
    ]),

    linkedIssues: asArray(
      issue?.linkedIssues ||
      issue?.issuelinks ||
      fields?.issuelinks ||
      row?.linkedIssues
    )
      .slice(0, 30)
      .map(normalizeLinkedIssue),

    comments,
    worklogs,
    changelog,

    commits: linkedCommits,

    evidenceAvailability: {
      jiraDescription: Boolean(
        issue?.description ||
        fields?.description ||
        row?.description
      ),

      jiraComments: comments.length,
      jiraWorklogs: worklogs.length,
      jiraChangelogEntries: changelog.length,
      commits: linkedCommits.length,
      commitsWithFiles: linkedCommits.filter(
        (commit) => commit.files.length > 0
      ).length,
      files: linkedCommits.reduce(
        (total, commit) => total + commit.files.length,
        0
      ),
    },
  };
}

const primarySis = rawWorkItems
  .filter((item) => item.role === 'primary')
  .map((item) => buildIssueEvidence(item, 'primarySis'));

const relatedSis = rawWorkItems
  .filter((item) => item.role === 'related')
  .map((item) => buildIssueEvidence(item, 'relatedSis'));

const recs = rawRecItems.map((item) => buildIssueEvidence(item, 'rec'));

const commitsWithoutSis = asArray(source.diagnostics?.commitsWithoutSIS)
  .slice(0, 80)
  .map((commit) => ({
    sha: commit.sha || null,
    shortSha: commit.sha ? String(commit.sha).slice(0, 10) : null,
    message: cut(commit.message, 900),
    isMergeCommit: Boolean(commit.isMergeCommit),
  }));

const fullEvidence = {
  release: {
    repository: release.repository || null,
    currentVersion: release.currentVersion || null,
    currentRef: release.currentRef || null,
    previousTag: release.previousTag || null,
  },

  diagnostics: source.diagnostics || {},

  primarySis,
  relatedSis,
  recs,

  commitsWithoutSis,

  sisWithoutRec: asArray(source.diagnostics?.sisWithoutREC).slice(0, 100),
};

const maxChars = Math.max(
  70000,
  Math.min(
    Number($json.aiPayloadMeta?.maxAiPayloadChars || 180000),
    260000
  )
);

// Se priorizan archivos y comentarios. Si hace falta recortar,
// se eliminan patches antes que archivos o contexto Jira.
function reduceForBudget(evidence) {
  const copy = JSON.parse(JSON.stringify(evidence));

  for (const issue of [...copy.primarySis, ...copy.relatedSis, ...copy.recs]) {
    for (const commit of issue.commits) {
      for (const file of commit.files) {
        file.patch = null;
      }
    }
  }

  return copy;
}

let evidence = fullEvidence;
let evidenceText = JSON.stringify(evidence, null, 2);
let budgetMode = 'full';

if (evidenceText.length > maxChars) {
  evidence = reduceForBudget(fullEvidence);
  evidenceText = JSON.stringify(evidence, null, 2);
  budgetMode = 'withoutPatches';
}

if (evidenceText.length > maxChars) {
  // Ãšltimo recorte: conserva todos los SIS, pero limita los comentarios largos
  // y archivos por commit; nunca vuelve a headerOnly.
  evidence = JSON.parse(JSON.stringify(evidence));

  for (const issue of [...evidence.primarySis, ...evidence.relatedSis, ...evidence.recs]) {
    issue.comments = issue.comments.slice(0, 8);
    issue.worklogs = issue.worklogs.slice(0, 8);
    issue.changelog = issue.changelog.slice(0, 12);

    for (const commit of issue.commits) {
      commit.files = commit.files.slice(0, 20);
    }
  }

  evidenceText = JSON.stringify(evidence, null, 2);
  budgetMode = 'compactEvidence';
}

